const config = $('Config Reporte').first().json;
const thresholdHours = Number(config.stale_threshold_hours || 24);
const timezone = config.timezone || 'America/Santiago';
const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();
const now = new Date();

function isEnabledFlag(value, defaultValue = true) {
  if (value === undefined || value === null || value === '') return defaultValue;
  if (typeof value === 'boolean') return value;
  const normalized = String(value).trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y', 'on', 'enabled'].includes(normalized);
}

const includeRequirements = isEnabledFlag(config.include_requirements, true);
const includeIncidents = isEnabledFlag(config.include_incidents, true);
const includeChanges = isEnabledFlag(config.include_changes, true);
const includeProblems = isEnabledFlag(config.include_problems, true);

const enabledTicketTypes = new Set();
if (includeRequirements) enabledTicketTypes.add('requirement');
if (includeIncidents) enabledTicketTypes.add('incident');
if (includeChanges) enabledTicketTypes.add('change');
if (includeProblems) enabledTicketTypes.add('problem');

function normalizeTicketKind(value, fields = {}) {
  const rawValues = [
    value,
    getField(fields, ['finalclass', 'class', 'class_friendlyname', 'ticket_class', 'ticket_type', 'type', 'request_type', 'request_type_friendlyname'], ''),
    getField(fields, ['ref', 'reference', 'friendlyname'], '')
  ].map(v => String(v || '').trim()).filter(Boolean);

  const raw = rawValues.join(' ').toLowerCase();

  if (raw.includes('userrequest') || raw.includes('user request') || raw.includes('request') || raw.includes('requerimiento') || raw.includes('requisito') || raw.includes('solicitud')) {
    return { key: 'requirement', label: 'Requerimiento' };
  }
  if (raw.includes('incident') || raw.includes('incidente') || raw.includes('incidencia')) {
    return { key: 'incident', label: 'Incidente' };
  }
  if (raw.includes('change') || raw.includes('cambio')) {
    return { key: 'change', label: 'Cambio' };
  }
  if (raw.includes('problem') || raw.includes('problema')) {
    return { key: 'problem', label: 'Problema' };
  }

  return { key: 'unknown', label: rawValues[0] || 'No identificado' };
}

function enabledTicketTypeText() {
  const labels = [];
  if (includeRequirements) labels.push('Requerimientos');
  if (includeIncidents) labels.push('Incidentes');
  if (includeChanges) labels.push('Cambios');
  if (includeProblems) labels.push('Problemas');
  return labels.length ? labels.join(', ') : 'Sin tipos habilitados';
}


function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function stripHtml(value) {
  return String(value ?? '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '\"')
    .replace(/&#039;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function rawField(obj, names) {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return undefined;
}

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}

function parseDate(value) {
  if (!value || value === '-') return null;
  if (value instanceof Date) return Number.isNaN(value.getTime()) ? null : value;
  const raw = String(value).trim();
  if (!raw) return null;
  const normalized = raw.includes('T') ? raw : raw.replace(' ', 'T');
  const d = new Date(normalized);
  return Number.isNaN(d.getTime()) ? null : d;
}

function fmtDateTime(value) {
  const d = parseDate(value);
  if (!d) return '-';
  return d.toLocaleString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
}

function diffHours(from, to = now) {
  const d = parseDate(from);
  if (!d) return 0;
  return Math.max(0, Math.floor((to.getTime() - d.getTime()) / 36e5));
}

function formatDurationFromHours(hours) {
  const h = Math.max(0, Math.floor(Number(hours || 0)));
  const days = Math.floor(h / 24);
  const rem = h % 24;
  if (days <= 0) return `${rem}h`;
  if (rem === 0) return `${days}d`;
  return `${days}d ${rem}h`;
}

function isBlank(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined' || v.toLowerCase() === 'n/a';
}

function closedSet() {
  return new Set(String(config.closed_status_values || '').split(',').map(v => v.trim().toLowerCase()).filter(Boolean));
}
function isClosed(status) { return closedSet().has(String(status || '').trim().toLowerCase()); }

function translateStatus(value) {
  const raw = String(value || '').trim();
  const s = raw.toLowerCase();
  const map = {
    new: 'Nuevo', assigned: 'Asignado', ongoing: 'En curso', pending: 'Pendiente', waiting: 'En espera', resolved: 'Resuelto', closed: 'Cerrado', rejected: 'Rechazado', cancelled: 'Cancelado'
  };
  return map[s] || raw || '-';
}

function collectLogEntries(value, collector = []) {
  if (value === undefined || value === null || value === '') return collector;
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = stripHtml(value);
    if (text && text !== '[object Object]') collector.push({ date: '', author: '', text });
    return collector;
  }
  if (Array.isArray(value)) { value.forEach(v => collectLogEntries(v, collector)); return collector; }
  if (typeof value === 'object') {
    const date = value.date || value.created || value.created_at || value.creation_date || value.timestamp || value.time || value.modification_date || '';
    const author = value.user_id_friendlyname || value.user_friendlyname || value.user_name || value.user_login || value.author || value.author_friendlyname || '';
    const direct = rawField(value, ['message', 'html', 'text', 'body', 'content', 'comment', 'note', 'entry', 'value', 'description']);
    if (direct !== undefined && direct !== value) {
      const text = stripHtml(direct);
      if (text && text !== '[object Object]') collector.push({ date, author, text });
    }
    const collection = value.entries || value.items || value.log || value.logs || value.records || value.data;
    if (collection && collection !== value) collectLogEntries(collection, collector);
  }
  return collector;
}

function getLastLog(fields) {
  const candidates = [
    rawField(fields, ['last_comment', 'last_note', 'last_public_log', 'last_private_log', 'last_update_reason', 'last_change']),
    rawField(fields, ['public_log', 'private_log', 'user_satisfaction', 'caselog', 'work_log', 'history'])
  ];
  const entries = [];
  for (const candidate of candidates) collectLogEntries(candidate, entries);
  const valid = entries.filter(e => e.text);
  if (!valid.length) return { text: '-', date: null };
  valid.sort((a, b) => (parseDate(a.date)?.getTime() || 0) - (parseDate(b.date)?.getTime() || 0));
  const last = valid[valid.length - 1];
  const prefix = [last.date ? fmtDateTime(last.date) : '', stripHtml(last.author)].filter(Boolean).join(' - ');
  return { text: prefix ? `${prefix}: ${last.text}` : last.text, date: parseDate(last.date) };
}

function detectLastUpdate(fields, createdAt) {
  const explicitUpdate = getField(fields, ['last_update','last_update_date','last_modification_date','last_modified','modification_date','date_mod','updated_at','last_activity','last_activity_date'], '');
  const explicitUpdateDate = parseDate(explicitUpdate);
  const lastLog = getLastLog(fields);
  const candidates = [explicitUpdateDate, lastLog.date].filter(Boolean).sort((a, b) => b.getTime() - a.getTime());
  return { date: candidates[0] || createdAt || null, source: candidates[0] ? 'update' : 'creation_fallback', note: lastLog.text || '-' };
}

function getSlaInfo(fields) {
  const raw = [getField(fields, ['tto_escalation_deadline', 'ttr_escalation_deadline', 'resolution_deadline'], ''), getField(fields, ['tto_escalation_flag', 'ttr_escalation_flag', 'sla_status', 'sla', 'slas'], '')].filter(Boolean).join(' ');
  const s = raw.toLowerCase();
  const breached = ['breach', 'breached', 'vencido', 'expired', 'late', 'rojo', 'red'].some(v => s.includes(v));
  return { text: raw || '-', breached };
}

function severityBadge(ticket) {
  if (ticket.slaBreached || ticket.hoursSinceUpdate >= 72 || ticket.ageDays > 14) return '<span class="badge badge-red">Crítico</span>';
  if (ticket.hoursSinceUpdate >= 48) return '<span class="badge badge-orange">Alto</span>';
  return '<span class="badge badge-yellow">Seguimiento</span>';
}

function td(value, align = 'left') {
  return `<td align="${align}" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${value}</td>`;
}
function th(text, align = 'left') {
  return `<th align="${align}" style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:${align}; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap;">${escapeHtml(text)}</th>`;
}

function ticketRow(ticket) {
  const note = ticket.lastNote && ticket.lastNote !== '-' ? ticket.lastNote : 'Sin anotación legible desde la respuesta de iTop';
  return `<tr>
    ${td(severityBadge(ticket))}
    ${td(`<strong>${escapeHtml(ticket.ref)}</strong>`)}
    ${td(`<strong>${escapeHtml(ticket.title)}</strong>`)}
    ${td(escapeHtml(ticket.caller))}
    ${td(escapeHtml(ticket.agent || 'Sin agente asignado'))}
    ${td(escapeHtml(fmtDateTime(ticket.createdAt)))}
    ${td(escapeHtml(fmtDateTime(ticket.lastUpdateAt)))}
    ${td(`<span class="badge ${ticket.hoursSinceUpdate >= 72 ? 'badge-red' : ticket.hoursSinceUpdate >= 48 ? 'badge-orange' : 'badge-yellow'}">${escapeHtml(formatDurationFromHours(ticket.hoursSinceUpdate))}</span>`)}
    ${td(escapeHtml(formatDurationFromHours(ticket.ageHours)))}
    ${td(ticket.slaBreached ? '<span class="badge badge-red">Vencido</span>' : escapeHtml(ticket.slaText || '-'))}
    ${td(`<span class="wrap">${escapeHtml(note).slice(0, 500)}</span>`)}
  </tr>`;
}

function renderAgentBlock(agent, tickets) {
  const sorted = [...tickets].sort((a, b) => (a.createdAt?.getTime() || 0) - (b.createdAt?.getTime() || 0));
  const oldest = sorted[0];
  const criticalCount = sorted.filter(t => t.slaBreached || t.hoursSinceUpdate >= 72 || t.ageDays > 14).length;
  const slaBreachedCount = sorted.filter(t => t.slaBreached).length;
  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:18px; border:1px solid #dbe3ec;">
    <tr><td style="background-color:#f1f5f9; padding:10px 12px; border-bottom:1px solid #dbe3ec;">
      <div style="font-size:14px; line-height:20px; font-weight:bold; color:#0f172a;">${escapeHtml(agent)} <span style="color:#64748b; font-weight:normal;">(${sorted.length} tickets)</span></div>
      <div style="font-size:12px; line-height:18px; color:#64748b; margin-top:4px;">Más antiguo: <strong>${escapeHtml(oldest?.ref || '-')}</strong> · abierto hace <strong>${escapeHtml(formatDurationFromHours(oldest?.ageHours || 0))}</strong> · críticos: <strong>${criticalCount}</strong> · SLA vencido: <strong>${slaBreachedCount}</strong></div>
    </td></tr>
    <tr><td><div class="table-scroll" style="width:100%; overflow-x:auto;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="data-table" style="width:100%;">
      <thead><tr>${th('Crit.')}${th('Referencia')}${th('Título / asunto')}${th('Solicitante')}${th('Agente')}${th('Creación')}${th('Último update')}${th('Sin update')}${th('Tiempo abierto')}${th('SLA')}${th('Última anotación / cambio registrado')}</tr></thead>
      <tbody>${sorted.map(ticketRow).join('')}</tbody>
    </table></div></td></tr>
  </table>`;
}

function renderSection(title, subtitle, tickets) {
  if (!tickets.length) return `<div class="section-title">${escapeHtml(title)}</div><div class="section-subtitle">${escapeHtml(subtitle)}</div><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec; margin-bottom:20px;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">Sin tickets para este bloque.</td></tr></table>`;
  const groups = new Map();
  for (const ticket of tickets) {
    const agent = ticket.agent || 'Sin agente asignado';
    if (!groups.has(agent)) groups.set(agent, []);
    groups.get(agent).push(ticket);
  }
  const ordered = Array.from(groups.entries()).sort(([, aList], [, bList]) => {
    const aOldest = Math.min(...aList.map(t => t.createdAt?.getTime() || Number.MAX_SAFE_INTEGER));
    const bOldest = Math.min(...bList.map(t => t.createdAt?.getTime() || Number.MAX_SAFE_INTEGER));
    return aOldest - bOldest;
  });
  return `<div class="section-title">${escapeHtml(title)}</div><div class="section-subtitle">${escapeHtml(subtitle)}</div>${ordered.map(([agent, list]) => renderAgentBlock(agent, list)).join('')}`;
}

const rows = flattenInput($input.all());
const tickets = rows.map((row) => {
  const f = row.fields || row;
  const status = getField(f, ['operational_status', 'operational_status_friendlyname', 'status', 'status_friendlyname'], '');
  const createdRaw = getField(f, ['start_date', 'creation_date', 'created_at', 'date', 'opened_at'], '');
  const createdAt = parseDate(createdRaw);
  const lastUpdate = detectLastUpdate(f, createdAt);
  const hoursSinceUpdate = diffHours(lastUpdate.date, now);
  const ageHours = diffHours(createdAt, now);
  const sla = getSlaInfo(f);
  const ticketKind = normalizeTicketKind(getField(f, ['finalclass', 'class', 'class_friendlyname', 'ticket_class', 'ticket_type', 'type'], ''), f);
  return {
    ref: getField(f, ['ref', 'reference', 'ticket_ref', 'friendlyname'], row.key || '-'),
    title: stripHtml(getField(f, ['title', 'description', 'name', 'friendlyname'], '-')),
    ticketType: ticketKind.key,
    ticketTypeLabel: ticketKind.label,
    status,
    statusLabel: translateStatus(status),
    caller: getField(f, ['caller_id_friendlyname', 'customer_id_friendlyname', 'requestor_id_friendlyname', 'person_id_friendlyname'], '-'),
    agent: getField(f, ['agent_id_friendlyname', 'agent_name', 'assignee_id_friendlyname', 'team_id_friendlyname', 'owner_id_friendlyname'], 'Sin agente asignado'),
    createdAt,
    lastUpdateAt: lastUpdate.date,
    lastUpdateSource: lastUpdate.source,
    lastNote: lastUpdate.note,
    hoursSinceUpdate,
    ageHours,
    ageDays: Math.floor(ageHours / 24),
    slaText: sla.text,
    slaBreached: sla.breached,
  };
})
.filter(t => !isClosed(t.status))
.filter(t => enabledTicketTypes.has(t.ticketType))
.filter(t => t.hoursSinceUpdate >= thresholdHours)
.sort((a, b) => (a.createdAt?.getTime() || 0) - (b.createdAt?.getTime() || 0));

const olderThan14 = tickets.filter(t => t.ageDays > 14);
const upTo14 = tickets.filter(t => t.ageDays <= 14);
const unassignedCount = tickets.filter(t => isBlank(t.agent) || t.agent === 'Sin agente asignado').length;
const stale72Count = tickets.filter(t => t.hoursSinceUpdate >= 72).length;
const stale48Count = tickets.filter(t => t.hoursSinceUpdate >= 48 && t.hoursSinceUpdate < 72).length;
const stale24Count = tickets.filter(t => t.hoursSinceUpdate >= 24 && t.hoursSinceUpdate < 48).length;
const slaBreachedCount = tickets.filter(t => t.slaBreached).length;
const oldestTicket = tickets[0] ? `${tickets[0].ref} · ${formatDurationFromHours(tickets[0].ageHours)}` : '-';
const agentCount = new Set(tickets.map(t => t.agent || 'Sin agente asignado')).size;

const generatedAt = now.toLocaleString('es-CL', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });

const older_section = renderSection('Tickets con más de 14 días abiertos', 'Agrupados por agente. Dentro de cada agente, ordenados desde el ticket más viejo al más nuevo. El filtro se aplica por último update mayor al umbral configurado.', olderThan14);
const recent_section = renderSection('Tickets abiertos hasta 14 días', 'Agrupados por agente. Dentro de cada agente, ordenados desde el ticket más viejo al más nuevo. El filtro se aplica por último update mayor al umbral configurado.', upTo14);

const csvHeaders = ['Criticidad','Referencia','Tipo','Titulo/Asunto','Estado','Solicitante','Agente','Creacion','Ultimo update','Horas sin update','Tiempo abierto horas','SLA','Ultima anotacion/cambio'];
const csvRows = tickets.map(t => [
  (t.slaBreached || t.hoursSinceUpdate >= 72 || t.ageDays > 14) ? 'Critico' : t.hoursSinceUpdate >= 48 ? 'Alto' : 'Seguimiento',
  t.ref, t.ticketTypeLabel, t.title, t.statusLabel, t.caller, t.agent, fmtDateTime(t.createdAt), fmtDateTime(t.lastUpdateAt), t.hoursSinceUpdate, t.ageHours, t.slaBreached ? 'Vencido' : t.slaText, t.lastNote
]);
const csvContent = '\uFEFF' + [csvHeaders.map(csvEscape).join(';'), ...csvRows.map(row => row.map(csvEscape).join(';'))].join('\r\n');
const generatedAtFile = new Date().toISOString().replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);

const subjectBase = String(config.email_subject || `Reporte ITSM - tickets sin update mayor a ${thresholdHours}h`).trim();
const emailSubject = itopOrganization ? `${subjectBase} - ${itopOrganization}` : subjectBase;

return [{
  json: {
    email_from: config.email_from,
    email_to: config.email_to,
    email_cc: config.email_cc || '',
    email_bcc: config.email_bcc || '',
    email_subject: emailSubject,
    company,
    Company: company,
    itop_organization: itopOrganization || '-',
    generated_at: generatedAt,
    threshold_hours: String(thresholdHours),
    enabled_ticket_types: enabledTicketTypeText(),
    include_requirements: String(includeRequirements),
    include_incidents: String(includeIncidents),
    include_changes: String(includeChanges),
    include_problems: String(includeProblems),
    total_stale: String(tickets.length),
    older_than_14_count: String(olderThan14.length),
    up_to_14_count: String(upTo14.length),
    stale_72h_count: String(stale72Count),
    stale_48h_count: String(stale48Count),
    stale_24h_count: String(stale24Count),
    unassigned_count: String(unassignedCount),
    sla_breached_count: String(slaBreachedCount),
    oldest_ticket: oldestTicket,
    agent_count: String(agentCount),
    older_section,
    recent_section,
    itop_url: config.itop_url || '#',
    csv_filename: `tickets_sin_update_${generatedAtFile}.csv`,
  },
  binary: {
    csv: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `tickets_sin_update_${generatedAtFile}.csv`,
    },
  },
}];

const input = $input.first();
const data = input.json || {};

const template = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Tickets abiertos sin update reciente</title>
  <style type="text/css">
    body { margin:0; padding:0; background-color:#eef2f6; font-family:Arial, Helvetica, sans-serif; color:#1f2937; }
    table { border-collapse:collapse; }
    a { color:#1d4ed8; text-decoration:none; }
    .wrapper { width:100%; background-color:#eef2f6; padding:24px 0; }
    .container { width:100%; max-width:1000px; background-color:#ffffff; border:1px solid #d9e2ec; }
    .mobile-padding { padding-left:28px; padding-right:28px; }
    .summary-card { padding:4px; }
    .data-table th { background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap; }
    .data-table td { font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top; }
    .section-title { font-size:18px; line-height:24px; font-weight:bold; color:#111827; margin-bottom:8px; }
    .section-subtitle { font-size:12px; line-height:18px; color:#6b7280; margin-bottom:10px; }
    .badge { display:inline-block; padding:4px 8px; border-radius:12px; font-size:11px; font-weight:bold; line-height:14px; white-space:nowrap; }
    .badge-red { background-color:#fee2e2; color:#991b1b; border:1px solid #fecaca; }
    .badge-orange { background-color:#ffedd5; color:#9a3412; border:1px solid #fed7aa; }
    .badge-yellow { background-color:#fef9c3; color:#854d0e; border:1px solid #fde68a; }
    .badge-green { background-color:#dcfce7; color:#166534; border:1px solid #bbf7d0; }
    .badge-blue { background-color:#dbeafe; color:#1e3a8a; border:1px solid #bfdbfe; }
    .badge-gray { background-color:#f3f4f6; color:#374151; border:1px solid #e5e7eb; }
    .wrap { word-break:break-word; overflow-wrap:break-word; }
    @media only screen and (max-width:760px) { .container{width:100%!important;} .mobile-padding{padding-left:14px!important;padding-right:14px!important;} .summary-card{width:100%!important;display:block!important;margin-bottom:8px!important;} .table-scroll{overflow-x:auto!important;display:block!important;width:100%!important;} }
  </style>
</head>
<body style="margin:0; padding:0; background-color:#eef2f6; font-family:Arial, Helvetica, sans-serif; color:#1f2937;">
  <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="wrapper"><tr><td align="center">
    <table role="presentation" width="1000" cellpadding="0" cellspacing="0" border="0" class="container">
      <tr><td style="background-color:#0f172a; padding:24px 28px;" class="mobile-padding">
        <table role="presentation" width="100%"><tr>
          <td valign="top" style="width:65%;">
            <div style="font-size:13px; line-height:18px; color:#93c5fd; font-weight:bold; letter-spacing:0.4px;">Automatización ITSM / Backlog</div>
